import{_ as i,o as t,c as a,ag as o}from"./chunks/framework.DTiDeF2Q.js";const g=JSON.parse('{"title":"Over Dotfiles (NL)","titleTemplate":":title","description":"De volgende generatie shell-configuratie. Hoge prestaties, veilig en AI-native. Beheerd door Chezmoi.","frontmatter":{"title":"Over Dotfiles","description":"De volgende generatie shell-configuratie. Hoge prestaties, veilig en AI-native. Beheerd door Chezmoi.","lang":"nl-NL","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Over Dotfiles preview","canonical":"/nl/about/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Over Dotfiles","pageType":"docs","schemaType":"WebPage","metaTitle":"Over Dotfiles - Dotfiles (NL)","permalink":"/nl/about/","meta":[{"name":"keywords","content":"chezmoi, dotfiles, configuratie, automatisering, macos, linux, rust, zellij, shell, terminal"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"De volgende generatie shell-configuratie. Hoge prestaties, veilig en AI-native. Beheerd door Chezmoi."},{"name":"twitter:title","content":"Over Dotfiles"},{"name":"og:title","content":"Over Dotfiles"},{"name":"og:description","content":"De volgende generatie shell-configuratie. Hoge prestaties, veilig en AI-native. Beheerd door Chezmoi."},{"name":"og:image:alt","content":"Dotfiles - Eenvoudig ontworpen om bij je shell-leven te passen"},{"name":"og:locale","content":"nl_NL"}]},"headers":[],"relativePath":"nl/about/index.md","filePath":"nl/about/index.md","lastUpdated":1773010926000}'),n={name:"nl/about/index.md"};function l(s,e,r,d,c,h){return t(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="over-dotfiles" tabindex="-1">Over Dotfiles <a class="header-anchor" href="#over-dotfiles" aria-label="Permalink to &quot;Over Dotfiles&quot;">​</a></h1><p>De moderne standaard voor shell-configuratie. Gebouwd op <strong>Chezmoi</strong> voor veilig, cross-platform omgevingsbeheer.</p><h2 id="ontdek" tabindex="-1">Ontdek <a class="header-anchor" href="#ontdek" aria-label="Permalink to &quot;Ontdek&quot;">​</a></h2><p>Dotfiles v0.2.495 transformeert je terminal in een krachtige, uniforme werkruimte. In tegenstelling tot oudere dotfiles die afhankelijk zijn van complexe Makefiles of symlink-scripts, gebruikt Dotfiles een template-gebaseerde aanpak die atomair, snel en reproduceerbaar is.</p><h3 id="wat-is-nieuw" tabindex="-1">Wat is nieuw <a class="header-anchor" href="#wat-is-nieuw" aria-label="Permalink to &quot;Wat is nieuw&quot;">​</a></h3><ul><li><strong>Moderne Kern</strong> — Hoogwaardige Rust-alternatieven vervangen oudere Unix-tools: <ul><li><strong>Atuin</strong> voor shell-geschiedenis</li><li><strong>Yazi</strong> voor bestandsbeheer</li><li><strong>Zellij</strong> voor terminal-multiplexing</li><li><strong>Ghostty</strong> voor GPU-versnelde terminal</li><li><strong>NeoVim</strong> voor modern bewerken</li></ul></li><li><strong>Native Beveiliging</strong> — Volledig native SSH-ondertekening zonder externe agents</li><li><strong>Interactieve Modus</strong> — Nieuw <code>dot learn</code> commando begeleidt je door de functies</li></ul><h2 id="aan-de-slag" tabindex="-1">Aan de slag <a class="header-anchor" href="#aan-de-slag" aria-label="Permalink to &quot;Aan de slag&quot;">​</a></h2><h3 id="vereisten" tabindex="-1">Vereisten <a class="header-anchor" href="#vereisten" aria-label="Permalink to &quot;Vereisten&quot;">​</a></h3><ul><li><strong>macOS</strong>, <strong>Linux (Ubuntu/Debian)</strong> of <strong>Windows (WSL)</strong></li><li><strong>Curl</strong> en <strong>Git</strong></li><li><strong>Chezmoi</strong> (wordt automatisch geinstalleerd)</li><li><strong>Nerd Font</strong> (voor terminal-iconen)</li></ul><h3 id="installeren" tabindex="-1">Installeren <a class="header-anchor" href="#installeren" aria-label="Permalink to &quot;Installeren&quot;">​</a></h3><p>Voer een enkel commando uit om de volledige suite te installeren:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sebastienrousseau/dotfiles/master/install.sh)&quot;</span></span></code></pre></div><p>De installer zal:</p><ol><li>De <code>chezmoi</code> binary installeren</li><li>De repository klonen</li><li>Vereiste pakketten installeren via Homebrew (macOS) of Apt (Linux)</li><li>Je configuratie toepassen</li></ol><h3 id="verkennen" tabindex="-1">Verkennen <a class="header-anchor" href="#verkennen" aria-label="Permalink to &quot;Verkennen&quot;">​</a></h3><p>Na de installatie herstart je terminal en voer uit:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> learn</span></span></code></pre></div><p>Dit start een interactieve rondleiding door je nieuwe omgeving.</p><h2 id="aanpassen" tabindex="-1">Aanpassen <a class="header-anchor" href="#aanpassen" aria-label="Permalink to &quot;Aanpassen&quot;">​</a></h2><p>Je configuratie bevindt zich in <code>~/.local/share/chezmoi</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.local/share/chezmoi</span></span>
<span class="line"><span>├── dot_zshenv              # Shell-ingangspunt</span></span>
<span class="line"><span>├── dot_config/             # XDG Base Config (~/.config)</span></span>
<span class="line"><span>│   ├── atuin/              # Shell-geschiedenis</span></span>
<span class="line"><span>│   ├── ghostty/            # Terminal-emulator</span></span>
<span class="line"><span>│   ├── git/                # Git-configuratie</span></span>
<span class="line"><span>│   ├── yazi/               # Bestandsbeheerder</span></span>
<span class="line"><span>│   ├── zellij/             # Terminal-multiplexer</span></span>
<span class="line"><span>│   ├── zsh/                # Zsh-configuratie</span></span>
<span class="line"><span>│   └── shell/              # Gedeelde aliassen en paden</span></span>
<span class="line"><span>├── provision/              # Levenscyclus-scripts</span></span>
<span class="line"><span>├── install.sh              # Universele installer</span></span>
<span class="line"><span>└── docs/                   # Documentatie</span></span></code></pre></div><h2 id="kerncommando-s" tabindex="-1">Kerncommando&#39;s <a class="header-anchor" href="#kerncommando-s" aria-label="Permalink to &quot;Kerncommando&#39;s&quot;">​</a></h2><p>De <code>dot</code>-CLI biedt 53 opdrachten, georganiseerd per categorie.</p><h3 id="kern" tabindex="-1">Kern <a class="header-anchor" href="#kern" aria-label="Permalink to &quot;Kern&quot;">​</a></h3><ul><li><code>dot apply</code> — past configuratiewijzigingen toe.</li><li><code>dot sync</code> — haalt de nieuwste repositorystatus op en past deze toe.</li><li><code>dot update</code> — werkt de repository bij en warmt caches op.</li><li><code>dot add</code> — voegt nieuwe bestanden toe aan de Chezmoi-bron.</li><li><code>dot diff</code> — toont openstaande wijzigingen vóór toepassing.</li><li><code>dot status</code> — toont de status van beheerde bestanden.</li><li><code>dot remove</code> — verwijdert een bestand uit beheer en wist de bronvermelding.</li><li><code>dot cd</code> — opent een shell in de Chezmoi-bronmap.</li><li><code>dot edit</code> — opent een beheerd bestand in uw editor.</li><li><code>dot clean-cache</code> — wist tijdelijke caches.</li><li><code>dot prewarm</code> — vult caches vooraf voor snellere shellstart.</li></ul><h3 id="diagnostiek" tabindex="-1">Diagnostiek <a class="header-anchor" href="#diagnostiek" aria-label="Permalink to &quot;Diagnostiek&quot;">​</a></h3><ul><li><code>dot doctor</code> — valideert paden, tools en shellstatus.</li><li><code>dot heal</code> — repareert ontbrekende of defecte status automatisch.</li><li><code>dot health</code> — voert een lichtgewicht gezondheidscontrole uit.</li><li><code>dot verify</code> — controleert bestandsintegriteit tegen de bron.</li><li><code>dot scorecard</code> — toont een configuratiekwaliteitsscore.</li><li><code>dot snapshot</code> — legt de huidige status vast voor latere vergelijking.</li><li><code>dot smoke-test</code> — valideert kerntoolchains volledig.</li><li><code>dot chaos</code> — injecteert fouten om zelfherstel te testen.</li><li><code>dot bundle</code> — exporteert een draagbaar configuratiepakket.</li><li><code>dot rollback</code> — keert terug naar een eerder snapshot.</li><li><code>dot drift</code> — detecteert onverwachte wijzigingen aan beheerde bestanden.</li><li><code>dot history</code> — toont het apply/sync-geschiedenislogboek.</li><li><code>dot benchmark</code> — meet de shellstarttijd.</li><li><code>dot perf</code> — profileert trage shellinitialisatie.</li></ul><h3 id="uiterlijk" tabindex="-1">Uiterlijk <a class="header-anchor" href="#uiterlijk" aria-label="Permalink to &quot;Uiterlijk&quot;">​</a></h3><ul><li><code>dot theme</code> — wisselt het kleurenschema van de terminal.</li><li><code>dot wallpaper</code> — stelt het bureaublad achtergrondafbeelding in (macOS).</li><li><code>dot fonts</code> — installeert of werkt Nerd Fonts bij.</li><li><code>dot tune</code> — past UI-dichtheid en promptstijl aan.</li></ul><h3 id="beveiliging" tabindex="-1">Beveiliging <a class="header-anchor" href="#beveiliging" aria-label="Permalink to &quot;Beveiliging&quot;">​</a></h3><ul><li><code>dot backup</code> — maakt versleutelde configuratieback-ups.</li><li><code>dot encrypt-check</code> — verifieert geheimversleuteling in rust.</li><li><code>dot firewall</code> — configureert host-firewallregels.</li><li><code>dot telemetry</code> — beheert anonieme gebruikstelemetrie.</li><li><code>dot dns-doh</code> — schakelt DNS-over-HTTPS in.</li><li><code>dot lock-screen</code> — vergrendelt het scherm onmiddellijk.</li><li><code>dot usb-safety</code> — beperkt automatisch koppelen van USB-massaopslag.</li></ul><h3 id="geheimen" tabindex="-1">Geheimen <a class="header-anchor" href="#geheimen" aria-label="Permalink to &quot;Geheimen&quot;">​</a></h3><ul><li><code>dot secrets-init</code> — initialiseert de geheimen-backend (age / GPG).</li><li><code>dot secrets</code> — toont versleutelde geheimvermeldingen.</li><li><code>dot secrets-create</code> — maakt een nieuw versleuteld geheim aan.</li><li><code>dot ssh-key</code> — genereert of roteert SSH-sleutelparen.</li><li><code>dot ssh-cert</code> — vraagt een SSH-certificaat aan bij een CA.</li></ul><h3 id="ai" tabindex="-1">AI <a class="header-anchor" href="#ai" aria-label="Permalink to &quot;AI&quot;">​</a></h3><ul><li><code>dot ai</code> — opent een interactieve AI-assistentsessie.</li><li><code>dot ai-setup</code> — configureert API-sleutels voor AI-providers.</li><li><code>dot ai-query</code> — stuurt een eenmalige prompt naar een AI-model.</li><li>AI-toolwrappers: <code>cl</code>, <code>gemini</code>, <code>kiro</code>, <code>sgpt</code>, <code>ollama</code>, <code>opencode</code>, <code>aider</code>.</li></ul><h3 id="gereedschap" tabindex="-1">Gereedschap <a class="header-anchor" href="#gereedschap" aria-label="Permalink to &quot;Gereedschap&quot;">​</a></h3><ul><li><code>dot tools</code> — toont meegeleverde CLI-vervangers en hun status.</li><li><code>dot new</code> — maakt een nieuw alias- of functiebestand aan.</li><li><code>dot sandbox</code> — opent een wegwerp-sandbox-shell.</li><li><code>dot keys</code> — toont huidige sneltoetsen.</li><li><code>dot learn</code> — start de interactieve tutorial.</li></ul><h3 id="meta" tabindex="-1">Meta <a class="header-anchor" href="#meta" aria-label="Permalink to &quot;Meta&quot;">​</a></h3><ul><li><code>dot upgrade</code> — upgradet Dotfiles naar de nieuwste versie.</li><li><code>dot packages</code> — toont geïnstalleerde pakketten beheerd door Dotfiles.</li><li><code>dot version</code> / <code>dot help</code> — toont versie- of gebruiksinformatie</li></ul><h2 id="bijdragen" tabindex="-1">Bijdragen <a class="header-anchor" href="#bijdragen" aria-label="Permalink to &quot;Bijdragen&quot;">​</a></h2><p>Word lid van de community. Bekijk onze <a href="https://github.com/sebastienrousseau/dotfiles/blob/master/.github/CODE-OF-CONDUCT.md" target="_blank" rel="noreferrer">Gedragscode</a> en <a href="https://github.com/sebastienrousseau/dotfiles/blob/master/.github/CONTRIBUTING.md" target="_blank" rel="noreferrer">Bijdrage-richtlijnen</a>.</p>`,41)])])}const u=i(n,[["render",l]]);export{g as __pageData,u as default};
